The Lost Citadel: Random Encounter Check.command:
// Uma Macro para gerar um encontro na Cidadela Perdida e exibi-lo apenas para o Mestre.;

const tableID = game.tables.find(o => o.name === "A Cidadela Perdida: Verificação de Encontro Aleatório")._id;
const table = await game.tables.get(tableID);
await table.draw({ rollMode: CONST.DICE_ROLL_MODES.PRIVATE});
